export function areaName(code: unknown, iso?: unknown, desc?: unknown): string {
  if (typeof desc === 'string' && desc.trim()) return desc.trim();
  const c = String(code ?? '').trim();
  if (c && COMTRADE_AREAS[c]) return COMTRADE_AREAS[c];
  if (typeof iso === 'string' && iso.trim()) return iso.trim();
  return c || 'Unknown';
}
